// ─── UTILITIES ────────────────────────────────────────────────────────────────

function formatDate(d) {
  if (!d) return "—";
  const [y, m, day] = d.split("-");
  const months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  return `${months[+m - 1]} ${+day}, ${y}`;
}

function generateICS(events) {
  const pad = (n) => String(n).padStart(2, "0");
  const toICSDate = (dateStr) => {
    if (!dateStr) return null;
    const d = new Date(dateStr + "T09:00:00");
    return `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}T090000`;
  };
  const uid = () => Math.random().toString(36).substr(2, 9) + "@feriatantoco.com";
  const lines = ["BEGIN:VCALENDAR","VERSION:2.0","PRODID:-//Feria Tantoco Daos//Matter Tracker//EN","CALSCALE:GREGORIAN","METHOD:PUBLISH"];
  events.forEach(({ summary, description, dateStr }) => {
    const dt = toICSDate(dateStr);
    if (!dt) return;
    lines.push("BEGIN:VEVENT",`UID:${uid()}`,
      `DTSTAMP:${toICSDate(new Date().toISOString().split("T")[0])}`,
      `DTSTART;VALUE=DATE:${dt.split("T")[0]}`,
      `DTEND;VALUE=DATE:${dt.split("T")[0]}`,
      `SUMMARY:${summary}`,
      `DESCRIPTION:${description.replace(/\n/g, "\\n")}`,
      "END:VEVENT");
  });
  lines.push("END:VCALENDAR");
  return lines.join("\r\n");
}

function downloadICS(content, filename) {
  const blob = new Blob([content], { type: "text/calendar;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}


// ─── MICROSOFT OUTLOOK CALENDAR SYNC — SCAFFOLD ──────────────────────────────
//
// STATUS: ⚠ PLACEHOLDER ONLY — NOT CONNECTED TO MICROSOFT GRAPH ⚠
//
// This section is a forward-compatible scaffold. All functions below simulate
// Outlook Calendar sync behaviour in-memory only. No data leaves the browser.
//
// ─────────────────────────────────────────────────────────────────────────────
// WHAT IS NEEDED FOR THE REAL IMPLEMENTATION (implementation checklist is
// provided separately below this app):
//
//  1. Microsoft Entra App Registration
//     • Register an app at https://portal.azure.com → Entra ID → App Registrations
//     • Set redirect URI (e.g. https://your-app.com/auth/callback or localhost)
//     • Note the Application (client) ID and Tenant ID
//
//  2. API Permissions (delegated, user-consent)
//     • Calendars.ReadWrite  (create / update / delete calendar events)
//     • User.Read            (get the logged-in user's profile)
//
//  3. OAuth 2.0 Sign-In (MSAL.js recommended)
//     • npm install @azure/msal-browser
//     • Acquire an access token with scopes: ["Calendars.ReadWrite","User.Read"]
//     • Store the token in memory (NOT localStorage) for the session
//
//  4. Microsoft Graph API endpoint
//     • Base URL: https://graph.microsoft.com/v1.0
//     • Create event:  POST /me/events
//     • Update event:  PATCH /me/events/{eventId}
//     • Delete event:  DELETE /me/events/{eventId}
//
//  5. Persistent event ID mapping
//     • Each stage that has been synced will receive an `outlookEventId`
//     • This ID must be stored server-side (Supabase, SharePoint Lists, etc.)
//       so it survives page refreshes. Currently stored in React state only.
//
//  6. Backend / secure token handling (production)
//     • For a Teams Tab app, use the Teams SSO token exchange
//     • For a standalone app, use MSAL redirect/popup flow
//     • Never expose client secrets in the browser bundle
//
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Builds the Microsoft Graph event payload from a matter + stage.
 * This shape is identical to what the real Graph API call will send.
 * Reference: https://learn.microsoft.com/en-us/graph/api/user-post-events
 */
function buildGraphEventPayload({ matter, stage, stageData }) {
  const associates = (matter.assignedAssociates || []).map(a => a.name).join(", ");
  const bodyContent = [
    `Matter: ${matter.name} (${matter.id})`,
    `Client: ${matter.client}`,
    `Practice Area: ${matter.practiceArea}`,
    `Stage: ${stage}`,
    `Partner: ${matter.assignedPartner?.name || "—"}`,
    `Associates: ${associates || "—"}`,
    `Responsible: ${stageData.responsible || "—"}`,
    `Notes: ${stageData.notes || "None"}`,
    "",
    "⚠ Synced via FeriaLaw Matter Tracker (placeholder sync)",
  ].join("\n");

  // Outlook requires ISO 8601 datetime strings in the user's timezone.
  // When real Graph is wired up, replace with the user's calendar timezone.
  const dueDateISO = stageData.dueDate
    ? `${stageData.dueDate}T09:00:00`
    : new Date().toISOString().split("T")[0] + "T09:00:00";
  const endDateISO = stageData.dueDate
    ? `${stageData.dueDate}T10:00:00`
    : new Date().toISOString().split("T")[0] + "T10:00:00";

  return {
    subject:  `[FTD] ${stage} — ${matter.name}`,
    body:     { contentType: "text", content: bodyContent },
    start:    { dateTime: dueDateISO,  timeZone: "Asia/Manila" },
    end:      { dateTime: endDateISO,  timeZone: "Asia/Manila" },
    isReminderOn: true,
    reminderMinutesBeforeStart: 60 * 24, // 1 day
    categories: ["FeriaLaw Matter Tracker"],
    // TODO (real impl): add attendees from stageData.responsibleEmail
    // attendees: stageData.responsibleEmail
    //   ? [{ emailAddress: { address: stageData.responsibleEmail }, type: "required" }]
    //   : [],
  };
}

