// ─── REMINDER / CALENDAR BUTTONS ─────────────────────────────────────────────

function ReminderCalendarButtons({ matter, stage, onStageUpdate }) {
  const sd = matter.stages[stage];
  if (!sd) return null;
  const { responsibleEmail: email, responsible: name, dueDate } = sd;

  // ── Outlook sync local state (drives spinner + optimistic UI) ──
  const [syncStatus, setSyncStatus] = useState(
    sd.outlookSyncStatus || OUTLOOK_SYNC_STATUS.NOT_SYNCED
  );
  const badge = OUTLOOK_SYNC_BADGE[syncStatus] || OUTLOOK_SYNC_BADGE["Not Synced"];

  // ── Existing: Send Reminder via mailto ────────────────────────
  const handleEmail = () => {
    if (!email) return;
    const subject = encodeURIComponent(`Reminder: ${stage} due for ${matter.name}`);
    const body = encodeURIComponent(
      `Dear ${name || "Colleague"},\n\nThis is a reminder that the "${stage}" stage for matter "${matter.name}" (${matter.id}) is due on ${formatDate(dueDate)}.\n\nClient: ${matter.client}\nPractice Area: ${matter.practiceArea}\n\nPlease ensure all deliverables are completed on time.\n\nBest regards,\nFeria Tantoco Daos — Matter Tracker`
    );
    window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;
  };

  // ── Existing: Download .ics file (fallback — always works) ────
  const handleCalendar = () => {
    if (!dueDate) return;
    const associates = matter.assignedAssociates.map(a => a.name).join(", ");
    const desc = `Matter: ${matter.name} (${matter.id})\\nClient: ${matter.client}\\nStage: ${stage}\\nPartner: ${matter.assignedPartner.name}\\nAssociates: ${associates}\\nNotes: ${sd.notes || "None"}`;
    const ics = generateICS([{ summary: `[FTD] ${stage} — ${matter.name}`, description: desc, dateStr: dueDate }]);
    downloadICS(ics, `${matter.id}-${stage.replace(/\s+/g, "_")}.ics`);
  };

  // ── NEW: Sync to Outlook (placeholder — Graph API not wired yet) ──
  const handleOutlookSync = async () => {
    if (!dueDate) {
      alert("A due date is required before syncing to Outlook.");
      return;
    }
    setSyncStatus(OUTLOOK_SYNC_STATUS.SYNCING);
    try {
      let result;
      if (sd.outlookEventId) {
        // Event already exists — update it
        result = await updateOutlookCalendarEventPlaceholder({
          eventId: sd.outlookEventId,
          matter,
          stage,
          stageData: sd,
        });
      } else {
        // First sync — create a new event
        result = await createOutlookCalendarEventPlaceholder({ matter, stage, stageData: sd });
      }

      if (result.success) {
        const updatedStageData = {
          ...sd,
          outlookEventId:       result.outlookEventId,
          outlookLastSyncedAt:  new Date().toISOString(),
          outlookSyncStatus:    OUTLOOK_SYNC_STATUS.SYNCED,
        };
        setSyncStatus(OUTLOOK_SYNC_STATUS.SYNCED);
        // Propagate updated stage data up so MatterDrawer / state can persist it
        if (onStageUpdate) onStageUpdate(stage, updatedStageData);
      } else {
        throw new Error("Placeholder returned success: false");
      }
    } catch (err) {
      console.error("[Outlook Scaffold] Sync failed:", err);
      setSyncStatus(OUTLOOK_SYNC_STATUS.SYNC_FAILED);
      if (onStageUpdate) {
        onStageUpdate(stage, { ...sd, outlookSyncStatus: OUTLOOK_SYNC_STATUS.SYNC_FAILED });
      }
    }
  };

  const isSyncing = syncStatus === OUTLOOK_SYNC_STATUS.SYNCING;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "6px", marginTop: "8px" }}>
      {/* Row 1 — existing buttons (unchanged) */}
      <div style={{ display: "flex", flexWrap: "wrap", gap: "6px" }}>
        {email && (
          <button onClick={handleEmail} style={{
            display: "inline-flex", alignItems: "center", gap: "4px",
            fontSize: "0.9375rem", padding: "5px 10px", borderRadius: "6px",
            border: `1px solid ${B.cobaltLight}`, background: B.cobaltTint,
            color: B.cobalt, fontFamily: "var(--font-ui)", cursor: "pointer",
          }}>
            <svg width="11" height="11" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
            Send Reminder
          </button>
        )}
        {dueDate && (
          <button onClick={handleCalendar} style={{
            display: "inline-flex", alignItems: "center", gap: "4px",
            fontSize: "0.9375rem", padding: "5px 10px", borderRadius: "6px",
            border: `1px solid ${B.goldLight}`, background: B.goldTint,
            color: "#7A6022", fontFamily: "var(--font-ui)", cursor: "pointer",
          }}>
            <svg width="11" height="11" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            Add to Calendar (.ics)
          </button>
        )}
      </div>

      {/* Row 2 — NEW Outlook sync row */}
      <div style={{ display: "flex", flexWrap: "wrap", alignItems: "center", gap: "6px" }}>
        {/* Sync status badge */}
        <span style={{
          display: "inline-flex", alignItems: "center", gap: "4px",
          fontSize: "0.875rem", padding: "4px 10px", borderRadius: "999px",
          background: badge.bg, color: badge.color,
          border: `1px solid ${badge.border}`,
          fontFamily: "var(--font-heading)", fontWeight: 600,
        }}>
          <span style={{ fontSize: isSyncing ? "0.8rem" : "0.7rem" }}>{badge.icon}</span>
          {syncStatus}
        </span>

        {/* Sync to Outlook button */}
        <button
          onClick={handleOutlookSync}
          disabled={isSyncing || !dueDate}
          title={
            !dueDate
              ? "Set a due date first"
              : syncStatus === OUTLOOK_SYNC_STATUS.SYNCED
              ? "Re-sync to update the existing Outlook event"
              : "⚠ Placeholder only — Microsoft Graph not connected yet"
          }
          style={{
            display: "inline-flex", alignItems: "center", gap: "4px",
            fontSize: "0.9375rem", padding: "5px 10px", borderRadius: "6px",
            border: "1px solid #8DB3E8",
            background: isSyncing ? "#D8E8F8" : "#EAF1FB",
            color: isSyncing ? "#6A9CC8" : "#1553A8",
            fontFamily: "var(--font-ui)", cursor: (isSyncing || !dueDate) ? "not-allowed" : "pointer",
            opacity: !dueDate ? 0.45 : 1,
          }}
        >
          {/* Outlook-style calendar icon */}
          <svg width="11" height="11" viewBox="0 0 20 20" fill="none">
            <rect x="1" y="3" width="18" height="15" rx="2" fill="#1553A8" opacity="0.15" stroke="#1553A8" strokeWidth="1.5"/>
            <path d="M1 7h18" stroke="#1553A8" strokeWidth="1.5"/>
            <rect x="5" y="1" width="2" height="4" rx="1" fill="#1553A8"/>
            <rect x="13" y="1" width="2" height="4" rx="1" fill="#1553A8"/>
            <path d="M5.5 11h3M5.5 14h5" stroke="#1553A8" strokeWidth="1.3" strokeLinecap="round"/>
          </svg>
          {isSyncing
            ? "Syncing…"
            : syncStatus === OUTLOOK_SYNC_STATUS.SYNCED
            ? "Re-sync to Outlook"
            : "Sync to Outlook"}
          <span style={{
            fontSize: "1rem", background: "#FFF3CD", color: "#856404",
            border: "1px solid #FFEEBA", borderRadius: "4px", padding: "0 4px",
            fontWeight: 700, letterSpacing: "0.02em",
          }}>DEMO</span>
        </button>

        {/* Show last synced time if available */}
        {sd.outlookLastSyncedAt && syncStatus === OUTLOOK_SYNC_STATUS.SYNCED && (
          <span style={{ fontSize: "0.875rem", color: "#AAA", fontFamily: "var(--font-ui)" }}>
            Last synced: {new Date(sd.outlookLastSyncedAt).toLocaleString()}
          </span>
        )}

        {/* Sync Failed helper text */}
        {syncStatus === OUTLOOK_SYNC_STATUS.SYNC_FAILED && (
          <span style={{ fontSize: "0.875rem", color: "#991B1B", fontFamily: "var(--font-ui)" }}>
            Sync failed — try again or use .ics fallback
          </span>
        )}
      </div>

      {/* Disclaimer — clearly labelled as placeholder */}
      <p style={{
        fontSize: "1rem", color: "#AAA", fontFamily: "var(--font-ui)",
        fontStyle: "italic", marginTop: "2px",
      }}>
        ⚠ Outlook sync is a placeholder. Microsoft Graph authentication is not yet configured.
      </p>
    </div>
  );
}


