                        display: "grid", gridTemplateColumns: "220px 1fr",
                        gap: "12px", alignItems: "start",
                        padding: "10px 14px", borderRadius: "8px",
                        background: j % 2 === 0 ? "#FAFAF7" : "#fff",
                        border: `1px solid ${B.rule}`,
